import React, { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { getProject, getTasks, createTask, updateTask, deleteTask, addMember, removeMember, submitTask, addComment, getTask } from '../utils/api';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { format, isPast } from 'date-fns';

export default function ProjectDetail() {
  const { id } = useParams();
  const { user, isAdmin } = useAuth();

  const [project, setProject] = useState(null);
  const [tasks, setTasks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showTaskModal, setShowTaskModal] = useState(false);
  const [showDetail, setShowDetail] = useState(null);
  const [taskForm, setTaskForm] = useState({ title:'', description:'', assignedTo:'', priority:'medium', deadline:'' });
  const [submissionNote, setSubmissionNote] = useState('');
  const [comment, setComment] = useState('');

  useEffect(() => { fetchAll(); }, [id]);

  const fetchAll = async () => {
    try {
      const [p, t] = await Promise.all([getProject(id), getTasks(id)]);
      setProject(p.data.project);
      setTasks(t.data.tasks);
    } catch { toast.error('Failed'); }
    finally { setLoading(false); }
  };

  const handleCreateTask = async (e) => {
    e.preventDefault();
    try {
      const res = await createTask({ ...taskForm, projectId:id });
      setTasks([res.data.task,...tasks]);
      setShowTaskModal(false);
      toast.success('Task created');
    } catch { toast.error('Failed'); }
  };

  const handleStatus = async (id, status) => {
    try {
      const res = await updateTask(id,{status});
      setTasks(tasks.map(t=>t._id===id?res.data.task:t));
      toast.success('Updated');
    } catch { toast.error('Failed'); }
  };

  const openDetail = async (taskId) => {
    try {
      const res = await getTask(taskId);
      setShowDetail(res.data.task);
    } catch { toast.error('Failed'); }
  };

  if (loading) return <div style={{textAlign:'center',padding:'60px',color:'#fff'}}>Loading...</div>;

  return (
    <div style={{minHeight:'100vh',padding:'30px',background:'linear-gradient(135deg,#0f172a,#022c22)'}}>

      {/* HEADER */}
      <div style={{marginBottom:'25px'}}>
        <Link to="/projects" style={{color:'#9ca3af',fontSize:'13px'}}>← Back</Link>

        <h1 style={{fontSize:'30px',color:'#4ade80',marginTop:'5px'}}>
          {project.name}
        </h1>

        {project.description && (
          <p style={{color:'#bbf7d0',fontSize:'14px'}}>
            {project.description}
          </p>
        )}
      </div>

      {/* ADD TASK */}
      {isAdmin && (
        <button onClick={()=>setShowTaskModal(true)}
          style={{marginBottom:'20px',padding:'10px 16px',background:'#22c55e',border:'none',borderRadius:'8px',color:'#022c22'}}>
          + Add Task
        </button>
      )}

      {/* TASK LIST */}
      <div style={{display:'grid',gridTemplateColumns:'repeat(2,1fr)',gap:'20px'}}>

        {tasks.map(task => {
          const overdue = task.deadline && isPast(new Date(task.deadline)) && task.status!=='completed';

          return (
            <div key={task._id}
              onClick={()=>openDetail(task._id)}
              style={{
                background:'rgba(255,255,255,0.06)',
                padding:'16px',
                borderRadius:'12px',
                cursor:'pointer',
                border:'1px solid rgba(255,255,255,0.1)'
              }}>

              <div style={{fontSize:'15px',fontWeight:'600',color:'#fff'}}>
                {task.title}
              </div>

              <div style={{fontSize:'12px',color:'#9ca3af',marginTop:'4px'}}>
                {task.description?.slice(0,60)}
              </div>

              <div style={{marginTop:'8px',fontSize:'12px',color:'#bbf7d0'}}>
                {task.assignedTo ? `👤 ${task.assignedTo.name}` : 'Unassigned'}
              </div>

              {task.deadline && (
                <div style={{fontSize:'12px',color:overdue?'#f87171':'#9ca3af'}}>
                  📅 {format(new Date(task.deadline),'MMM dd')}
                </div>
              )}

              <div style={{marginTop:'8px',fontSize:'12px',color:'#e5e7eb'}}>
                {task.status}
              </div>

            </div>
          );
        })}

      </div>

      {/* TASK MODAL */}
      {showTaskModal && (
        <div onClick={e=>e.target===e.currentTarget && setShowTaskModal(false)}
          style={{position:'fixed',top:0,left:0,right:0,bottom:0,background:'rgba(0,0,0,0.6)',display:'flex',alignItems:'center',justifyContent:'center'}}>

          <div style={{background:'#111827',padding:'25px',borderRadius:'12px',width:'400px'}}>

            <h2 style={{color:'#4ade80'}}>Create Task</h2>

            <form onSubmit={handleCreateTask}>

              <input placeholder="Title"
                onChange={e=>setTaskForm({...taskForm,title:e.target.value})}
                style={{width:'100%',marginTop:'10px',padding:'10px',background:'#020617',color:'#fff',border:'1px solid #374151'}}/>

              <textarea rows={3} placeholder="Description"
                onChange={e=>setTaskForm({...taskForm,description:e.target.value})}
                style={{width:'100%',marginTop:'10px',padding:'10px',background:'#020617',color:'#fff',border:'1px solid #374151'}}/>

              <input type="date"
                onChange={e=>setTaskForm({...taskForm,deadline:e.target.value})}
                style={{width:'100%',marginTop:'10px',padding:'10px',background:'#020617',color:'#fff',border:'1px solid #374151'}}/>

              <button type="submit"
                style={{marginTop:'15px',width:'100%',padding:'10px',background:'#22c55e',border:'none',color:'#022c22'}}>
                Create
              </button>

            </form>
          </div>
        </div>
      )}

      {/* DETAIL MODAL */}
      {showDetail && (
        <div onClick={e=>e.target===e.currentTarget && setShowDetail(null)}
          style={{position:'fixed',top:0,left:0,right:0,bottom:0,background:'rgba(0,0,0,0.6)',display:'flex',justifyContent:'center',alignItems:'center'}}>

          <div style={{background:'#111827',padding:'20px',borderRadius:'12px',width:'500px'}}>

            <h2 style={{color:'#4ade80'}}>{showDetail.title}</h2>

            <p style={{color:'#9ca3af'}}>{showDetail.description}</p>

            <div style={{marginTop:'10px',fontSize:'13px',color:'#bbf7d0'}}>
              Status: {showDetail.status}
            </div>

            {/* MEMBER ACTION */}
            {!isAdmin && showDetail.assignedTo?._id === user._id && (
              <div style={{marginTop:'15px'}}>
                <textarea placeholder="Submission note"
                  value={submissionNote}
                  onChange={e=>setSubmissionNote(e.target.value)}
                  style={{width:'100%',padding:'8px',background:'#020617',color:'#fff'}}/>

                <button onClick={()=>handleStatus(showDetail._id,'review')}
                  style={{marginTop:'8px',padding:'8px',background:'#22c55e',border:'none',color:'#022c22'}}>
                  Submit
                </button>
              </div>
            )}

            {/* COMMENTS */}
            <div style={{marginTop:'15px'}}>
              <input placeholder="Comment..."
                value={comment}
                onChange={e=>setComment(e.target.value)}
                style={{width:'100%',padding:'8px',background:'#020617',color:'#fff'}}/>

              <button onClick={()=>addComment(showDetail._id,{text:comment})}
                style={{marginTop:'8px',padding:'6px 10px',background:'#22c55e',border:'none',color:'#022c22'}}>
                Send
              </button>
            </div>

            <button onClick={()=>setShowDetail(null)}
              style={{marginTop:'15px',background:'#374151',border:'none',padding:'8px',color:'#fff'}}>
              Close
            </button>

          </div>
        </div>
      )}

    </div>
  );
}
